/* Icon-only: fixed square from density height (hug). Fill stretches the hit target. */
:host(.button-filled-host--icon.ds-control-width--hug) {
  width: var(--ds-control-height, var(--dimension-size-400));
  height: var(--ds-control-height, var(--dimension-size-400));
  min-width: var(--ds-control-height, var(--dimension-size-400));
  min-height: var(--ds-control-height, var(--dimension-size-400));
}

:host(.button-filled-host--icon.ds-control-width--fill) {
  height: var(--ds-control-height, var(--dimension-size-400));
  min-height: var(--ds-control-height, var(--dimension-size-400));
}

:host(.ds-control-width--fill) .button-filled {
  width: 100%;
}

.button-filled {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  height: var(--ds-control-height, var(--dimension-size-400));
  padding: 0 var(--ds-control-padding-inline, var(--dimension-space-075));
  gap: var(--ds-control-gap, var(--dimension-space-050));
  border: none;
  border-radius: var(--ds-control-radius, var(--dimension-radius-025));
  background-color: var(--ds-button-filled-bg);
  color: var(--ds-button-filled-fg);
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  overflow: hidden;
  transition:
    background-color var(--effect-motion-short-2),
    color var(--effect-motion-short-2),
    transform var(--effect-motion-short-2);
  /* Hover/press: `.ds-interaction-fill` + contrast → `--on-*` (token overlay, not color-mix). */
}

.button-filled--icon {
  width: 100%;
  height: 100%;
  padding: 0;
}

.button-filled:active:not(:disabled):not(.ds-control-inactive) {
  transform: scale(var(--dimension-scale-subtle));
}

/* Inactive: `.ds-control-inactive` (25% opacity). */

.button-filled__icon-wrap {
  position: relative;
  width: var(--ds-control-icon, var(--dimension-iconography-md));
  height: var(--ds-control-icon, var(--dimension-iconography-md));
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  z-index: 2;
}

.button-filled__label {
  position: relative;
  z-index: 2;
  padding: 0 var(--ds-control-label-inset, var(--dimension-space-025));
  white-space: nowrap;
  flex-shrink: 0;
  min-width: 0;
}

